import{_ as a,o as t,c as n,a0 as s}from"./chunks/framework.DTwdCQre.js";const m=JSON.parse('{"title":"Release Hygiene","description":"","frontmatter":{},"headers":[],"relativePath":"release-hygiene.md","filePath":"release-hygiene.md","lastUpdated":1777729439000}'),i={name:"release-hygiene.md"};function r(l,e,d,o,c,p){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="release-hygiene" tabindex="-1">Release Hygiene <a class="header-anchor" href="#release-hygiene" aria-label="Permalink to &quot;Release Hygiene&quot;">​</a></h1><p>This page is the source-of-truth checklist for keeping OpenSpec changes, docs, generated artifacts, and release claims aligned.</p><h2 id="openspec-hygiene-checklist" tabindex="-1">OpenSpec Hygiene Checklist <a class="header-anchor" href="#openspec-hygiene-checklist" aria-label="Permalink to &quot;OpenSpec Hygiene Checklist&quot;">​</a></h2><ul><li>Active implementation changes are small enough to implement, verify, and archive as one coherent unit.</li><li>Umbrella changes are labeled as planning artifacts and are not applied directly as large mixed-scope implementation work.</li><li>Every active or release-bound spec has a concrete purpose and testable scenarios.</li><li><code>openspec validate &lt;change&gt; --strict</code> passes before implementation completion and before archive.</li><li>Completed tasks include evidence or an explicit validation gap.</li></ul><h2 id="task-evidence-format" tabindex="-1">Task Evidence Format <a class="header-anchor" href="#task-evidence-format" aria-label="Permalink to &quot;Task Evidence Format&quot;">​</a></h2><p>Use this format when checking off tasks:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Evidence:</span></span>
<span class="line"><span>- command or test name</span></span>
<span class="line"><span>- relevant artifact path</span></span>
<span class="line"><span>- result summary</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Not-tested:</span></span>
<span class="line"><span>- explicit gap, or &quot;none&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="archive-readiness" tabindex="-1">Archive Readiness <a class="header-anchor" href="#archive-readiness" aria-label="Permalink to &quot;Archive Readiness&quot;">​</a></h2><p>Before archiving a change:</p><ul><li>All tasks are checked or deliberately carried forward.</li><li>Evidence is recorded in <code>tasks.md</code>, implementation notes, or release notes.</li><li><code>go test ./...</code> passes for code changes.</li><li><code>./scripts/run-harness.sh</code> passes when agent behavior or release evidence changes.</li><li>Docs source and generated output policy is followed.</li><li><code>openspec validate &lt;change&gt; --strict</code> passes.</li></ul><h2 id="active-change-inventory" tabindex="-1">Active Change Inventory <a class="header-anchor" href="#active-change-inventory" aria-label="Permalink to &quot;Active Change Inventory&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Change</th><th>Type</th><th>Evidence expectation</th></tr></thead><tbody><tr><td><code>agent-roadmap-audit-and-hardening</code></td><td>Umbrella roadmap</td><td>Keep as planning context; do not apply directly as one implementation unit.</td></tr><tr><td><code>fix-core-runtime-safety</code></td><td>Implementation</td><td>Go tests, trace fixtures, TUI cancellation tests, OpenSpec validation.</td></tr><tr><td><code>productize-extension-boundaries</code></td><td>Implementation</td><td>MCP/LSP/hooks/skills/provider tests, doctor/replay diagnostics, OpenSpec validation.</td></tr><tr><td><code>harness-agent-quality-gates</code></td><td>Implementation</td><td>Pytest harness, deterministic harness command, Go tests, OpenSpec validation.</td></tr><tr><td><code>openspec-docs-release-hygiene</code></td><td>Implementation</td><td>Docs inventory, hygiene script, install smoke, OpenSpec validation.</td></tr></tbody></table><h2 id="release-state-matrix" tabindex="-1">Release State Matrix <a class="header-anchor" href="#release-state-matrix" aria-label="Permalink to &quot;Release State Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>State</th><th>Required evidence</th></tr></thead><tbody><tr><td>Local/dev</td><td><code>go test ./...</code>, targeted tests for changed packages, active change validation.</td></tr><tr><td>Release candidate</td><td>Local/dev evidence, <code>./scripts/run-harness.sh</code>, docs source check, install smoke, known gaps.</td></tr><tr><td>Published</td><td>Release-candidate evidence, CI green, release notes, artifact checksums when applicable, docs deployment result.</td></tr></tbody></table><h2 id="known-gaps" tabindex="-1">Known Gaps <a class="header-anchor" href="#known-gaps" aria-label="Permalink to &quot;Known Gaps&quot;">​</a></h2><ul><li>External-agent comparison evidence is manual and must be labeled as such.</li><li>Generated docs under <code>docs/.vitepress/dist</code> are release artifacts, not the review source of truth.</li><li>Publishing may require remote credentials and CI permissions outside local verification.</li></ul>`,16)])])}const u=a(i,[["render",r]]);export{m as __pageData,u as default};
